css:
.loader {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
   width: 20px;
   height: 80px;
   background: var(--loader-color, #e11d48);
   position: relative;
}
.loader:before  {
  content: "";
   position: absolute;
   top: 10px;
   left: -22px;
   width: 25px;
   height: 60px;
   background: radial-gradient(farthest-side,currentColor 92%,#0000) 60% 6px/4px 4px, radial-gradient(50% 60%,var(--loader-secondary-color, #fb7185) 92%,#0000) center/70% 55%, radial-gradient(farthest-side,var(--loader-secondary-color, #fb7185) 92%,#0000) 50% 3px/14px 14px, radial-gradient(142% 100% at bottom right,#0000 64%,var(--loader-secondary-color, #fb7185) 65%) bottom/57% 40%, conic-gradient(from -120deg at right,var(--loader-secondary-color, #fb7185) 36deg,#0000 0)100% 3px/51% 12px, conic-gradient(from 120deg at top left,#0000 ,#ef524a 2deg 40deg,#0000 43deg) top/100% 10px;
   background-repeat: no-repeat;
   transform: rotate(-26deg);
   transform-origin: 100% 80%;
   animation: l16 .25s infinite linear alternate;
}
.loader:after  {
  content: "";
   position: absolute;
   width: 6px;
   height: 12px;
   left: -6px;
   bottom: 15px;
   border-radius: 100px 0 0 100px;
   background: var(--loader-secondary-color, #fb7185);
}
@keyframes l16  {
  100% {transform: rotate(0)}
}
